import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CurrentConsumption {
  value: number;
  unit: string;
  cost: number;
  currency: string;
}

interface DailyCost {
  value: number;
  currency: string;
}

interface EnergyUsageData {
  currentConsumption: CurrentConsumption;
  dailyCost: DailyCost;
  usageTrend: number[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const data = response.data as EnergyUsageData;
  const meta = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Current Consumption
            </Typography>
            <Typography variant="h4" fontWeight={500} sx={{ color: meta.primaryColor }}>
              {data.currentConsumption.value} {data.currentConsumption.unit}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Cost: {data.currentConsumption.currency} {data.currentConsumption.cost}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Daily Cost
            </Typography>
            <Typography variant="h5" fontWeight={500} sx={{ color: meta.accentColor }}>
              {data.dailyCost.currency} {data.dailyCost.value}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: data.usageTrend,
                  color: meta.primaryColor,
                  curve: 'natural',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'linear',
                  data: data.usageTrend.map((_, i) => i),
                  id: 'usageTrend',
                },
              ]}
              yAxis={[{ id: 'consumption' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="usageTrend"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="consumption"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
